/**
 * Flavor Theme — Client-side Search
 *
 * Fetches /api/search.json (generated by Gridea Pro at build time) on first
 * open, then performs real-time fuzzy search with CJK awareness, keyboard
 * navigation, highlighted excerpts, and full accessibility support.
 *
 * Pure vanilla JS, no dependencies.
 */
; (function () {
  'use strict';

  // -- Constants --------------------------------------------------------------
  var SEARCH_JSON_URL = '/api/search.json';
  var DEBOUNCE_MS = 150;
  var EXCERPT_RADIUS = 40;   // chars each side of match (~80 total)
  var ACTIVE_CLASS = 'is-active';
  var WEIGHT_TITLE = 10;
  var WEIGHT_CONTENT = 1;

  // -- State ------------------------------------------------------------------
  var posts = null;  // cached JSON — null means "not yet fetched"
  var isLoading = false;
  var debounceId = null;
  var activeIdx = -1;    // highlighted result index

  // -- DOM refs (resolved lazily) ---------------------------------------------
  var overlay, modal, input, results, closeBtn;

  function resolveDOM() {
    if (overlay) return;
    overlay = document.getElementById('searchOverlay');
    modal = overlay ? overlay.querySelector('.search-modal') : null;
    input = document.getElementById('searchInput');
    results = document.getElementById('searchResults');
    closeBtn = document.getElementById('searchClose');
  }

  // -- Data fetching (lazy-load once, cache in memory) ------------------------
  function ensureData(cb) {
    if (posts !== null) return cb();
    if (isLoading) return;
    isLoading = true;
    showMsg('加载中...');

    var xhr = new XMLHttpRequest();
    xhr.open('GET', SEARCH_JSON_URL, true);
    xhr.onreadystatechange = function () {
      if (xhr.readyState !== 4) return;
      isLoading = false;
      try { posts = xhr.status === 200 ? JSON.parse(xhr.responseText) : []; }
      catch (_) { posts = []; }
      cb();
    };
    xhr.send();
  }

  // -- Open / Close -----------------------------------------------------------
  function openSearch() {
    resolveDOM();
    if (!overlay) return;
    overlay.style.display = '';
    overlay.setAttribute('aria-hidden', 'false');
    input.value = '';
    activeIdx = -1;
    document.body.style.overflow = 'hidden';
    showRecommendations();
    requestAnimationFrame(function () { input.focus(); });
  }

  /** Show latest posts as recommendations when search opens (no query). */
  function showRecommendations() {
    if (!results || !posts || !posts.length) {
      if (results) results.innerHTML = '';
      return;
    }
    var recent = posts.slice(0, 8);
    var html = '';
    for (var i = 0; i < recent.length; i++) {
      var p = recent[i];
      html += '<a class="search-result-item" href="' + esc(p.link) + '"'
        + ' role="option" aria-selected="false">'
        + '<div class="search-result-item__title">' + esc(p.title) + ' <span class="search-arrow">→</span></div>'
        + '<div class="search-result-item__excerpt">' + esc((p.content || '').substring(0, 50) + ((p.content || '').length > 50 ? '...' : '')) + '</div>'
        + '<div class="search-result-item__date">' + esc(p.date) + '</div>'
        + '</a>';
    }
    results.innerHTML = html;
  }

  function closeSearch() {
    if (!overlay) return;
    overlay.style.display = 'none';
    overlay.setAttribute('aria-hidden', 'true');
    document.body.style.overflow = '';
  }

  // -- Message helpers --------------------------------------------------------
  function showMsg(text) {
    if (results) results.innerHTML = '<div class="search-empty">' + esc(text) + '</div>';
  }

  // -- Search algorithm -------------------------------------------------------
  /** Score a single post. Returns { score, titleHL, excerptHL } or null. */
  function scorePost(post, query) {
    var lq = query.toLowerCase();
    var lt = (post.title || '').toLowerCase();
    var lc = (post.content || '').toLowerCase();
    var ti = lt.indexOf(lq);
    var ci = lc.indexOf(lq);

    if (ti === -1 && ci === -1) return null;

    // Relevance: weight + positional bonus (earlier = better)
    var score = 0;
    if (ti !== -1) score += WEIGHT_TITLE * (1 + 1 / (1 + ti));
    if (ci !== -1) score += WEIGHT_CONTENT * (1 + 1 / (1 + ci));

    // Highlighted title
    var titleHL = ti !== -1
      ? hlMatch(post.title, ti, query.length)
      : esc(post.title);

    // Excerpt with highlight (or plain opening if match is content-only)
    var excerptHL;
    if (ci !== -1) {
      excerptHL = buildExcerpt(post.content, ci, query.length);
    } else {
      var plain = (post.content || '').substring(0, EXCERPT_RADIUS * 2);
      excerptHL = esc(plain) + (plain.length < (post.content || '').length ? '...' : '');
    }

    return { score: score, titleHL: titleHL, excerptHL: excerptHL };
  }

  /** Run search against all cached posts and render the results list. */
  function executeSearch(query) {
    if (!results) return;
    var q = (query || '').trim();
    if (!q) { showRecommendations(); activeIdx = -1; return; }

    var matched = [];
    for (var i = 0; i < posts.length; i++) {
      var hit = scorePost(posts[i], q);
      if (hit) {
        matched.push({
          link: posts[i].link, date: posts[i].date || '',
          titleHL: hit.titleHL, excerptHL: hit.excerptHL, score: hit.score
        });
      }
    }

    matched.sort(function (a, b) { return b.score - a.score; });

    if (!matched.length) { showMsg('未找到相关文章'); activeIdx = -1; return; }

    var html = '';
    for (var j = 0; j < matched.length; j++) {
      var m = matched[j];
      html += '<a class="search-result-item" href="' + esc(m.link) + '"'
        + ' role="option" aria-selected="false">'
        + '<div class="search-result-item__title">' + m.titleHL + ' <span class="search-arrow">→</span></div>'
        + '<div class="search-result-item__excerpt">' + m.excerptHL + '</div>'
        + '<div class="search-result-item__date">' + esc(m.date) + '</div>'
        + '</a>';
    }
    results.innerHTML = html;
    activeIdx = -1;
  }

  // -- Highlighting & excerpt helpers -----------------------------------------
  /** Wrap `len` chars at `idx` in <mark>, escape the rest. */
  function hlMatch(text, idx, len) {
    return esc(text.substring(0, idx))
      + '<mark>' + esc(text.substring(idx, idx + len)) + '</mark>'
      + esc(text.substring(idx + len));
  }

  /** Short excerpt centred on match position with <mark>. */
  function buildExcerpt(content, idx, len) {
    var start = Math.max(0, idx - EXCERPT_RADIUS);
    var end = Math.min(content.length, idx + len + EXCERPT_RADIUS);
    var prefix = start > 0 ? '...' : '';
    var suffix = end < content.length ? '...' : '';
    return prefix
      + esc(content.substring(start, idx))
      + '<mark>' + esc(content.substring(idx, idx + len)) + '</mark>'
      + esc(content.substring(idx + len, end))
      + suffix;
  }

  // -- Keyboard navigation ----------------------------------------------------
  function resultItems() {
    return results ? results.querySelectorAll('.search-result-item') : [];
  }

  function setActive(newIdx) {
    var items = resultItems();
    if (!items.length) return;

    // Clear previous
    if (activeIdx >= 0 && activeIdx < items.length) {
      items[activeIdx].classList.remove(ACTIVE_CLASS);
      items[activeIdx].setAttribute('aria-selected', 'false');
    }

    // Wrap around
    if (newIdx < 0) newIdx = items.length - 1;
    if (newIdx >= items.length) newIdx = 0;
    activeIdx = newIdx;

    items[activeIdx].classList.add(ACTIVE_CLASS);
    items[activeIdx].setAttribute('aria-selected', 'true');
    items[activeIdx].scrollIntoView({ block: 'nearest' });
  }

  function openActive() {
    var items = resultItems();
    if (activeIdx >= 0 && activeIdx < items.length) {
      window.location.href = items[activeIdx].getAttribute('href');
    }
  }

  // -- Focus trap (keep Tab cycling inside modal) -----------------------------
  function trapFocus(e) {
    if (!modal || e.key !== 'Tab') return;
    var els = modal.querySelectorAll(
      'input, button, a[href], [tabindex]:not([tabindex="-1"])'
    );
    if (!els.length) return;
    var first = els[0], last = els[els.length - 1];
    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault(); last.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault(); first.focus();
    }
  }

  // -- Utilities --------------------------------------------------------------
  function esc(s) {
    if (!s) return '';
    return s.replace(/&/g, '&amp;').replace(/</g, '&lt;')
      .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }

  function debounce(fn, ms) {
    return function () {
      var ctx = this, args = arguments;
      clearTimeout(debounceId);
      debounceId = setTimeout(function () { fn.apply(ctx, args); }, ms);
    };
  }

  // -- Event binding ----------------------------------------------------------
  function bindEvents() {
    resolveDOM();
    if (!overlay || !input || !results || !closeBtn) return;

    // Open: .search-btn click
    var btns = document.querySelectorAll('.search-btn');
    for (var i = 0; i < btns.length; i++) {
      btns[i].addEventListener('click', function (e) {
        e.preventDefault();
        ensureData(openSearch);
      });
    }

    // Open: Cmd+K / Ctrl+K
    document.addEventListener('keydown', function (e) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        ensureData(openSearch);
      }
    });

    // Close: button, overlay background, Escape
    closeBtn.addEventListener('click', closeSearch);
    overlay.addEventListener('click', function (e) {
      if (e.target === overlay) closeSearch();
    });

    // Real-time search with debounce
    var debouncedSearch = debounce(function () {
      executeSearch(input.value);
    }, DEBOUNCE_MS);
    input.addEventListener('input', debouncedSearch);

    // Keyboard navigation inside overlay
    overlay.addEventListener('keydown', function (e) {
      switch (e.key) {
        case 'Escape': e.preventDefault(); closeSearch(); break;
        case 'ArrowDown': e.preventDefault(); setActive(activeIdx + 1); break;
        case 'ArrowUp': e.preventDefault(); setActive(activeIdx - 1); break;
        case 'Enter':
          if (activeIdx >= 0) { e.preventDefault(); openActive(); }
          break;
      }
      trapFocus(e);
    });
  }

  // -- Init -------------------------------------------------------------------
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', bindEvents);
  } else {
    bindEvents();
  }
})();
